        "@context": "https://schema.nfh.global/DEGContract/v2.0/context.jsonld",
        "@type": "DEGContract",
        "roles": [{"role": "buyer", "participantId": "tpddl-north-delhi"}, {"role": "seller", "participantId": "greenflex-agg"}],
